#include <bits/stdc++.h>
using namespace std;
bool is_prime(int n){
    if(n<2)return false;
    for(int i=2;i*i<=n;i++)
        if(n%i==0)return false;
    return true;
}
int main(){
    int n;
    cin>>n;
    for(int i=n/2;i>1;i--){
        if(n%i==0 && is_prime(i) && is_prime(n/i)){
            cout<<i;
            break;
        }
    }
    return 0;
}
